sys_script_include.script:
var discordNotification = Class.create();
discordNotification.prototype = {
    initialize: function() {
        this.webhook = gs.getProperty('x_1534869_wrm.discord.webhook_url');
    },
    sendMessage: function(message, emoji) {
        try {
            var payload = {
                content: (emoji || '') + ' ' + message
            };
            var r = new sn_ws.RESTMessageV2();
            r.setEndpoint(this.webhook);
            r.setHttpMethod('post');
            r.setRequestHeader("Content-Type", "application/json");
            r.setRequestBody(JSON.stringify(payload));
            var response = r.execute();
            gs.info('Discord Notification Sent: ' + response.getStatusCode());
        } catch (ex) {
            gs.error('Discord Notification Error: ' + ex.message);
        }
    },
    type: 'discordNotification'
};
